      {
        "parameters": {
          "description": "Deep-analyze a business idea using real-time market research (Perplexity + Tavily). Returns market context with figures, strengths, weaknesses, opportunities, and a potential score (1-10). Use when the user presents a business idea or startup concept that needs validation and market analysis.",
          "workflowId": {
